-- ADR-0031 Phase 3 — seed _chat_mutation_log_config (20 rules from doc 140340 §SQL)
-- Idempotent: ON CONFLICT DO NOTHING uses the (table_id, column_key) unique index.
-- Rules cover Tickets (1708), _registry (2197), bdd_criteria (7256), bdd_specs (7255),
-- ADR Projects (1699), Bugs (1552). Space-level emission gated by env
-- ROW_MUTATION_LOG_ENABLED_SPACES — empty by default; flipped to "11" on DEV at P3.

ON CONFLICT (table_id, column_key) DO NOTHING;
